/**
 * Theme definitions for T3 Code.
 *
 * Each theme specifies semantic color tokens, typography defaults, and an
 * implicit light/dark base mode.  The web app applies these tokens as CSS
 * custom properties on the document root so every Tailwind / CSS-variable-aware
 * component picks them up automatically.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const FONT_FAMILY_SANS =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#0c0c0e",
      statusBar: "#111113",
    },
    fontFamily: FONT_FAMILY_SANS,
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c1e",
      accent: "#4f46e5",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#f8f8f8",
      statusBar: "#f0f0f0",
    },
    fontFamily: FONT_FAMILY_SANS,
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0d1117",
      foreground: "#c9d1d9",
      accent: "#58a6ff",
      sidebar: "#010409",
      editor: "#0d1117",
      terminal: "#010409",
      statusBar: "#161b22",
    },
    fontFamily: FONT_FAMILY_SANS,
    fontSize: 14,
  },
] as const;

// ---------------------------------------------------------------------------
// Lookup helpers
// ---------------------------------------------------------------------------

const themeMap = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

/** Default theme applied when no preference has been stored. */
export const DEFAULT_THEME_ID = "t3-dark";

/**
 * Return the theme for the given `id`.
 * Falls back to the default theme when the id is unknown.
 */
export function getTheme(id: string): Theme {
  return themeMap.get(id) ?? themeMap.get(DEFAULT_THEME_ID)!;
}

/** Return all built-in themes in display order. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

