import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type Theme,
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
} from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";

// ---------------------------------------------------------------------------
// CSS custom-property mapping
// ---------------------------------------------------------------------------

const COLOR_PROPERTIES: ReadonlyArray<{ key: keyof Theme["colors"]; prop: string }> = [
  { key: "background", prop: "--theme-background" },
  { key: "foreground", prop: "--theme-foreground" },
  { key: "accent", prop: "--theme-accent" },
  { key: "sidebar", prop: "--theme-sidebar" },
  { key: "editor", prop: "--theme-editor" },
  { key: "terminal", prop: "--theme-terminal" },
  { key: "statusBar", prop: "--theme-status-bar" },
];

// ---------------------------------------------------------------------------
// External store (shared across all hook instances)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: { themeId: string } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

/** Resolve a stored value to a valid theme ID, migrating legacy values. */
function resolveStoredId(raw: string | null): string {
  if (!raw) return DEFAULT_THEME_ID;

  // Migrate legacy light/dark/system values from the old hook
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") return DEFAULT_THEME_ID;

  // For any other value, getTheme already falls back to the default
  return getTheme(raw).id;
}

function getStored(): string {
  return resolveStoredId(localStorage.getItem(STORAGE_KEY));
}

function isDarkTheme(themeId: string): boolean {
  return themeId !== "t3-light";
}

function applyCssProperties(theme: Theme) {
  const root = document.documentElement;
  for (const { key, prop } of COLOR_PROPERTIES) {
    root.style.setProperty(prop, theme.colors[key]);
  }
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
}

function applyTheme(themeId: string, suppressTransitions = false) {
  const theme = getTheme(themeId);

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  document.documentElement.classList.toggle("dark", isDarkTheme(themeId));
  applyCssProperties(theme);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): { themeId: string } {
  const themeId = getStored();
  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }
  lastSnapshot = { themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(snapshot.themeId);
  const resolvedTheme: "light" | "dark" = isDarkTheme(snapshot.themeId) ? "dark" : "light";
  const availableThemes = listThemes();

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(snapshot.themeId);
  }, [snapshot.themeId]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

