import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch – miniature preview of a theme's color palette
// ---------------------------------------------------------------------------

function ThemeSwatch({ theme, active }: { theme: Theme; active: boolean }) {
  return (
    <div
      className={`flex h-10 w-14 shrink-0 overflow-hidden rounded-md border transition-shadow ${
        active ? "border-primary ring-2 ring-primary/30" : "border-border"
      }`}
    >
      {/* Sidebar sliver */}
      <div className="w-3.5" style={{ backgroundColor: theme.colors.sidebar }} />
      {/* Editor + status-bar */}
      <div className="flex flex-1 flex-col">
        <div className="flex-1" style={{ backgroundColor: theme.colors.editor }}>
          {/* Accent dot to hint at the accent color */}
          <div
            className="ml-1 mt-1.5 size-1.5 rounded-full"
            style={{ backgroundColor: theme.colors.accent }}
          />
        </div>
        <div className="h-1.5" style={{ backgroundColor: theme.colors.statusBar }} />
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {availableThemes.map((t) => {
        const selected = activeTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatch theme={t} active={selected} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                {/* Color chips */}
                {(["background", "accent", "sidebar"] as const).map((key) => (
                  <span
                    key={key}
                    className="inline-block size-2.5 rounded-full border border-border/60"
                    style={{ backgroundColor: t.colors[key] }}
                  />
                ))}
                <span className="ml-0.5">{t.id}</span>
              </span>
            </span>
            {selected ? (
              <span className="ml-auto shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

